    /// <summary>
    /// Initializes the current <c>VendInvoiceJour</c> table record based on the data in the specified
    /// <c>VendInvoiceInfoTable</c> table record.
    /// </summary>
    /// <param name="_vendInvoiceInfoTable">
    /// The <c>VendInvoiceInfoTable</c> table record that contains the data to copy.
    /// </param>
    public void initFromVendInvoiceInfoTable(VendInvoiceInfoTable _vendInvoiceInfoTable)
    {
        next initFromVendInvoiceInfoTable(_vendInvoiceInfoTable);

        this.UBSHasWarrantyRetention = _vendInvoiceInfoTable.UBSHasWarrantyRetention;
        this.UBSWarrantyRate = _vendInvoiceInfoTable.UBSWarrantyRate;
    }

    void initFromVendTrans(VendTrans vendTrans)
    {
        next initFromVendTrans(vendTrans);

        this.UBSWarrantyRefInvoice = vendTrans.UBSWarrantyRefInvoice;
    }

    public static VendInvoiceJour findWarrantyRefInvoice(RefRecId _refRecId)
    {
        VendInvoiceJour vendInvoiceJour;

        select firstfast vendInvoiceJour 
               where vendInvoiceJour.UBSWarrantyRefInvoice == _refRecId;

        return vendInvoiceJour;
    }
